"use strict";(self.webpackChunkadvance_import_export_woocommerce=self.webpackChunkadvance_import_export_woocommerce||[]).push([[6006],{8898(t,e,s){s.r(e),s.d(e,{comp:()=>a,data:()=>r});var o=s(641);const n={},a=(0,s(6262).A)(n,[["render",function(t,e){const s=(0,o.g2)("RouteLink");return(0,o.uX)(),(0,o.CE)("div",null,[e[14]||(e[14]=(0,o.Fv)('<h1 id="dashboard" tabindex="-1"><a class="header-anchor" href="#dashboard"><span>Dashboard</span></a></h1><p>The Dashboard is the first page you land on when clicking <strong>Webkul WC Addons → Import Export</strong> in your sidebar. It shows stats, recent activity, quick action buttons, and a system info check.</p><p><strong>Page URL:</strong> <code>/wp-admin/admin.php?page=wkaie</code></p><p><strong>Page title at the top:</strong> &quot;Advance Import Export&quot; (with a database import icon)</p><p><strong>Subtitle:</strong> &quot;Import &amp; export millions of WooCommerce products, orders, customers, and more.&quot;</p><p><img src="/advance-import-export-woocommerce/images/dashboard-top.webp" alt="Dashboard top section"><em>Dashboard — stat cards, quick actions, and recent activity.</em></p><h2 id="the-4-stat-cards" tabindex="-1"><a class="header-anchor" href="#the-4-stat-cards"><span>The 4 Stat Cards</span></a></h2><p>Four cards sit at the top in a grid.</p><table><thead><tr><th>#</th><th>Card Title</th><th>What It Shows</th><th>Icon</th></tr></thead><tbody><tr><td>1</td><td><strong>Total Jobs</strong></td><td>All saved jobs (enabled + disabled)</td><td>List icon, blue</td></tr><tr><td>2</td><td><strong>Active Schedules</strong></td><td>Jobs with cron schedule turned on</td><td>Clock icon, green</td></tr><tr><td>3</td><td><strong>Failed (Last 24h)</strong></td><td>Runs that failed in the past 24 hours</td><td>Warning icon, red if &gt; 0</td></tr><tr><td>4</td><td><strong>Total Records Imported</strong></td><td>Lifetime total records</td><td>Database import icon, orange</td></tr></tbody></table><p>Click <strong>Failed (Last 24h)</strong> to jump to History filtered by failed status.</p><h2 id="quick-actions-card" tabindex="-1"><a class="header-anchor" href="#quick-actions-card"><span>Quick Actions Card</span></a></h2><p><strong>Heading:</strong> &quot;Quick Actions&quot; (with a performance icon)</p><p>Three buttons in a horizontal row:</p><table><thead><tr><th>Button</th><th>Goes To</th></tr></thead><tbody><tr><td><strong>New Import</strong> (blue primary button)</td><td>Quick Import Wizard</td></tr><tr><td><strong>New Export</strong> (gray secondary button)</td><td>Quick Export page</td></tr><tr><td><strong>Run Health Check</strong> (gray secondary button)</td><td>Health Check page</td></tr></tbody></table><h2 id="recent-activity-card" tabindex="-1"><a class="header-anchor" href="#recent-activity-card"><span>Recent Activity Card</span></a></h2><p><strong>Heading:</strong> &quot;Recent Activity&quot; (with a backup icon)</p><p>Shows the last 10 runs. If no runs yet:</p><blockquote><p>&quot;No import/export activity yet. Start your first import above.&quot;</p></blockquote><p>When runs exist, you see a table with these columns:</p><table><thead><tr><th>Column</th><th>What It Shows</th></tr></thead><tbody><tr><td><strong>Status</strong></td><td>Green check (success) / red X (failed) / orange clock (running)</td></tr><tr><td><strong>Job Title</strong></td><td>Name of the job, or &quot;Quick Import&quot; if run from wizard</td></tr><tr><td><strong>Entity Type</strong></td><td>Products, Orders, etc.</td></tr><tr><td><strong>Records</strong></td><td>Created / Updated / Failed counts</td></tr><tr><td><strong>Duration</strong></td><td>How long the run took</td></tr><tr><td><strong>Time Ago</strong></td><td>&quot;5 min ago&quot;, &quot;2 hours ago&quot;, etc.</td></tr></tbody></table><p>Click any row to open the full run in the History page.</p><p>At the bottom of the card: <strong>View Full History</strong> button.</p><div class="hint-container tip"><p class="hint-container-title">&quot;Run did not start&quot; in the Records column</p><p>If a run crashed before processing any rows (e.g., file not found), the Records column shows &quot;Run did not start&quot; instead of &quot;0 / 0 / 0&quot;. Click for full error details.</p></div><h2 id="system-information-card" tabindex="-1"><a class="header-anchor" href="#system-information-card"><span>System Information Card</span></a></h2><p>The most important card — it checks every server requirement.</p><p><img src="/advance-import-export-woocommerce/images/dashboard-system-info.webp" alt="System Information card"><em>System Info — green good, yellow warning, red needs attention.</em></p><h3 id="status-banner-at-top" tabindex="-1"><a class="header-anchor" href="#status-banner-at-top"><span>Status Banner at Top</span></a></h3><p>The banner summarizes:</p><table><thead><tr><th>Banner</th><th>Meaning</th></tr></thead><tbody><tr><td>Green: &quot;All system requirements met. Your server is fully optimized for high-speed imports.&quot;</td><td>Everything works</td></tr><tr><td>Yellow: &quot;X performance warnings.&quot;</td><td>Works but slower than possible</td></tr><tr><td>Red: &quot;X critical issues detected.&quot;</td><td>Fix these first</td></tr><tr><td>Yellow + Red: &quot;X critical issue(s) and Y warning(s) detected. Expand each row below for fix instructions.&quot;</td><td>Mixed</td></tr></tbody></table><h3 id="what-s-checked" tabindex="-1"><a class="header-anchor" href="#what-s-checked"><span>What&#39;s Checked</span></a></h3><table><thead><tr><th>#</th><th>Row</th><th>Minimum</th><th>What It Means</th></tr></thead><tbody><tr><td>1</td><td><strong>PHP Version</strong></td><td>8.1</td><td>Your PHP version</td></tr><tr><td>2</td><td><strong>MySQL Version</strong></td><td>8.0</td><td>Your MySQL/MariaDB</td></tr><tr><td>3</td><td><strong>WordPress Version</strong></td><td>6.0</td><td>Your WordPress</td></tr><tr><td>4</td><td><strong>WooCommerce Version</strong></td><td>8.0</td><td>Your WooCommerce</td></tr><tr><td>5</td><td><strong>pcntl Extension</strong></td><td>Recommended</td><td>Enables parallel processing (10x speed)</td></tr><tr><td>6</td><td><strong>posix Extension</strong></td><td>Recommended</td><td>Enables FIFO pipes</td></tr><tr><td>7</td><td><strong>LOAD DATA LOCAL INFILE</strong></td><td>Required</td><td>MySQL flag for fastest bulk insert</td></tr><tr><td>8</td><td><strong>MyISAM Engine</strong></td><td>Optional</td><td>2x speed boost for staging</td></tr><tr><td>9</td><td><strong>PHP Memory Limit</strong></td><td>256M+</td><td>Memory per PHP process</td></tr><tr><td>10</td><td><strong>PHP Max Execution Time</strong></td><td>300s+</td><td>Max script run time</td></tr></tbody></table><h3 id="each-row-shows" tabindex="-1"><a class="header-anchor" href="#each-row-shows"><span>Each Row Shows</span></a></h3><ul><li><strong>Name</strong> on the left</li><li><strong>Value</strong> in the middle (your current value)</li><li><strong>Status</strong> on the right: <ul><li>Green checkmark + &quot;Available&quot; (good)</li><li>Red X + &quot;Not Available&quot; (need to fix)</li><li>Yellow warning icon (suboptimal)</li></ul></li></ul><h3 id="how-to-fix-this-sections" tabindex="-1"><a class="header-anchor" href="#how-to-fix-this-sections"><span>&quot;How to Fix This&quot; Sections</span></a></h3><p>Any row with a red X or yellow warning has an expandable section labeled <strong>How to fix this</strong>.</p><p>Click to expand. The plugin auto-detects your server OS and shows the right commands:</p><p><strong>For pcntl missing on Ubuntu:</strong></p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line"><span class="token function">sudo</span> <span class="token function">apt-get</span> <span class="token function">install</span> php8.3-pcntl</span>\n<span class="line"><span class="token function">sudo</span> systemctl restart php8.3-fpm</span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>For pcntl missing on CentOS / RHEL:</strong></p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line"><span class="token function">sudo</span> dnf <span class="token function">install</span> php-process</span>\n<span class="line"><span class="token function">sudo</span> systemctl restart php-fpm</span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>For pcntl missing on macOS:</strong></p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line">brew <span class="token function">install</span> php@8.3</span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>For Windows:</strong></p><blockquote><p>&quot;pcntl is not supported on Windows. Use WSL2 or a Linux server.&quot;</p></blockquote><p><strong>For LOAD DATA LOCAL INFILE disabled, three options:</strong></p><p><strong>Option 1 — SQL as admin:</strong></p><div class="language-sql line-numbers-mode" data-highlighter="prismjs" data-ext="sql"><pre><code><span class="line"><span class="token keyword">SET</span> <span class="token keyword">GLOBAL</span> local_infile <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span></span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>Option 2 — Permanent in my.cnf:</strong></p><div class="language-ini line-numbers-mode" data-highlighter="prismjs" data-ext="ini"><pre><code><span class="line"><span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">mysqld</span><span class="token punctuation">]</span></span></span>\n<span class="line"><span class="token key attr-name">local_infile</span> <span class="token punctuation">=</span> <span class="token value attr-value">1</span></span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>Then restart MySQL.</p><p><strong>Option 3 — Ask your host:</strong></p><blockquote><p>Copy-paste this message: &quot;Please enable LOAD DATA LOCAL INFILE for my MySQL user. The plugin requires this for bulk imports.&quot;</p></blockquote><h3 id="buttons-at-the-bottom" tabindex="-1"><a class="header-anchor" href="#buttons-at-the-bottom"><span>Buttons at the Bottom</span></a></h3><table><thead><tr><th>Button</th><th>What It Does</th></tr></thead><tbody><tr><td><strong>Expand all fix instructions</strong></td><td>Opens every &quot;How to fix&quot; box at once</td></tr><tr><td><strong>Copy system info for support</strong></td><td>Copies the whole system info table to your clipboard</td></tr></tbody></table><p>Use <strong>Copy system info for support</strong> when opening a support ticket.</p><h2 id="troubleshooting-the-dashboard" tabindex="-1"><a class="header-anchor" href="#troubleshooting-the-dashboard"><span>Troubleshooting the Dashboard</span></a></h2><table><thead><tr><th>Problem</th><th>Fix</th></tr></thead><tbody><tr><td>All stat cards show 0</td><td>You have not run any imports yet. Click <strong>New Import</strong></td></tr><tr><td>Dashboard takes a long time to load</td><td>Your database may be slow. Clean old history: <code>wp wkaie history cleanup --older-than=30d</code></td></tr><tr><td>&quot;Failed (Last 24h)&quot; shows a high number</td><td>Open History, inspect each failed run for the error message</td></tr><tr><td>System info shows pcntl &quot;Not Available&quot;</td><td>Expand &quot;How to fix this&quot; for install commands</td></tr><tr><td>&quot;PHP Memory Limit&quot; shows yellow</td><td>Add <code>define(&#39;WP_MEMORY_LIMIT&#39;, &#39;512M&#39;);</code> to <code>wp-config.php</code></td></tr><tr><td>&quot;LOAD DATA LOCAL INFILE&quot; shows red</td><td>Run the SQL or ask your host</td></tr></tbody></table><h2 id="related-pages" tabindex="-1"><a class="header-anchor" href="#related-pages"><span>Related Pages</span></a></h2>',58)),(0,o.Lk)("ul",null,[(0,o.Lk)("li",null,[(0,o.bF)(s,{to:"/installation.html"},{default:(0,o.k6)(()=>[...e[0]||(e[0]=[(0,o.eW)("Installation",-1)])]),_:1}),e[1]||(e[1]=(0,o.eW)(" — Initial setup",-1))]),(0,o.Lk)("li",null,[(0,o.bF)(s,{to:"/first-time-setup.html"},{default:(0,o.k6)(()=>[...e[2]||(e[2]=[(0,o.eW)("First-Time Setup",-1)])]),_:1}),e[3]||(e[3]=(0,o.eW)(" — Step-by-step checklist",-1))]),(0,o.Lk)("li",null,[(0,o.bF)(s,{to:"/quick-import.html"},{default:(0,o.k6)(()=>[...e[4]||(e[4]=[(0,o.eW)("Quick Import Wizard",-1)])]),_:1}),e[5]||(e[5]=(0,o.eW)(" — Start importing",-1))]),(0,o.Lk)("li",null,[(0,o.bF)(s,{to:"/history.html"},{default:(0,o.k6)(()=>[...e[6]||(e[6]=[(0,o.eW)("History",-1)])]),_:1}),e[7]||(e[7]=(0,o.eW)(" — Full run history",-1))]),(0,o.Lk)("li",null,[(0,o.bF)(s,{to:"/health-check.html"},{default:(0,o.k6)(()=>[...e[8]||(e[8]=[(0,o.eW)("Health Check",-1)])]),_:1}),e[9]||(e[9]=(0,o.eW)(" — Find and fix data issues",-1))]),(0,o.Lk)("li",null,[(0,o.bF)(s,{to:"/settings.html"},{default:(0,o.k6)(()=>[...e[10]||(e[10]=[(0,o.eW)("Settings",-1)])]),_:1}),e[11]||(e[11]=(0,o.eW)(" — Change defaults",-1))]),(0,o.Lk)("li",null,[(0,o.bF)(s,{to:"/php-configuration.html"},{default:(0,o.k6)(()=>[...e[12]||(e[12]=[(0,o.eW)("PHP Configuration",-1)])]),_:1}),e[13]||(e[13]=(0,o.eW)(" — Fix PHP limits",-1))])])])}]]),r=JSON.parse('{"path":"/dashboard.html","title":"Dashboard — What You See First","lang":"en-US","frontmatter":{"title":"Dashboard — What You See First","description":"A walkthrough of the plugin dashboard. Stat cards, quick actions, recent activity, and system information with fix-it guides.","meta":[{"name":"keywords","content":"woocommerce import dashboard, wordpress admin dashboard, system info, quick actions"}]},"headers":[{"level":2,"title":"The 4 Stat Cards","slug":"the-4-stat-cards","link":"#the-4-stat-cards","children":[]},{"level":2,"title":"Quick Actions Card","slug":"quick-actions-card","link":"#quick-actions-card","children":[]},{"level":2,"title":"Recent Activity Card","slug":"recent-activity-card","link":"#recent-activity-card","children":[]},{"level":2,"title":"System Information Card","slug":"system-information-card","link":"#system-information-card","children":[{"level":3,"title":"Status Banner at Top","slug":"status-banner-at-top","link":"#status-banner-at-top","children":[]},{"level":3,"title":"What\'s Checked","slug":"what-s-checked","link":"#what-s-checked","children":[]},{"level":3,"title":"Each Row Shows","slug":"each-row-shows","link":"#each-row-shows","children":[]},{"level":3,"title":"\\"How to Fix This\\" Sections","slug":"how-to-fix-this-sections","link":"#how-to-fix-this-sections","children":[]},{"level":3,"title":"Buttons at the Bottom","slug":"buttons-at-the-bottom","link":"#buttons-at-the-bottom","children":[]}]},{"level":2,"title":"Troubleshooting the Dashboard","slug":"troubleshooting-the-dashboard","link":"#troubleshooting-the-dashboard","children":[]},{"level":2,"title":"Related Pages","slug":"related-pages","link":"#related-pages","children":[]}],"git":{},"filePathRelative":"dashboard.md"}')}}]);